INSERT INTO contact_inquiries (
  name, email, phone, inquiry_type, message, status, created_at, updated_at
) VALUES (
  #{name}, #{email}, #{phone}, #{inquiryType}, #{message}, #{status}, CURRENT_TIMESTAMP, CURRENT_TIMESTAMP
)

mapper.select:
SELECT id, name, email, phone, inquiry_type, message, status, created_at, updated_at FROM contact_inquiries WHERE 1 = 1
AND ( LOWER(name) LIKE CONCAT('%', LOWER(#{query}), '%') OR LOWER(email) LIKE CONCAT('%', LOWER(#{query}), '%') OR LOWER(message) LIKE CONCAT('%', LOWER(#{query}), '%') )
AND status = #{status}
ORDER BY created_at DESC, id DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM contact_inquiries WHERE 1 = 1
AND ( LOWER(name) LIKE CONCAT('%', LOWER(#{query}), '%') OR LOWER(email) LIKE CONCAT('%', LOWER(#{query}), '%') OR LOWER(message) LIKE CONCAT('%', LOWER(#{query}), '%') )
AND status = #{status}

SELECT id, name, email, phone, inquiry_type, message, status, created_at, updated_at
FROM contact_inquiries
WHERE id = #{id}
